import path from "path"
import { fileURLToPath } from "url"

import {  source, sources } from "datool"
import { SAMPLE_JSONL, type SampleWorkflowRow } from "./sample-workflow-data"

const currentDirectory = path.dirname(fileURLToPath(import.meta.url))

type DemoRow = Record<string, unknown> & {
  message: string
}

export type ToyTraceRow =
  | {
      type: "span"
      spanId: string
      parentSpanId?: string
      name: string
      resource: "workflow" | "database" | "function" | "step"
      startTime: string
      endTime: string
      activeStartTime?: string
      attributes?: Record<string, unknown>
    }
  | {
      type: "event"
      spanId: string
      name: string
      timestamp: string
      color?: string
      showVerticalLine?: boolean
      attributes?: Record<string, unknown>
    }

export type ToyTraceGroupRow = {
  id: string
  displayName: string
  traces: ToyTraceRow[]
}

export const demo = source<DemoRow>({
  actions: {
    delete: {
      button: "destructive",
      icon: "Trash",
      label: "Abort Run",
      async resolve({ rows }) {
        await Promise.resolve(new Promise((resolve) => setTimeout(resolve, 1000)))
        return rows.map(() => false)
      },
    },
    abort: {
      button: "outline",
      icon: "Trash",
      label: "Abort Run",
      resolve({ rows }) {
        return rows.map((row) => ({
          ...row,
          message: `[aborted] ${String(row.message ?? "")}`,
        }))
      },
    },
  },
  label: "Command JSONL",
  stream: sources.command({
    command: ({ query }) =>
      `bun run ${path.join(currentDirectory, "..", "scripts/emit-jsonl.ts")} ${
        query.get("history") ?? "24"
      }`,
  }),
})
function parseJSONL<Row>(input: string): Row[] {
  return input
    .trim()
    .split("\n")
    .filter(Boolean)
    .map((line) => JSON.parse(line) as Row)
}


export const sampleWorkflow = source<SampleWorkflowRow>({
  get({ limit, offset, page }) {
    const rows = parseJSONL<SampleWorkflowRow>(SAMPLE_JSONL)
    const resolvedLimit = limit ?? rows.length
    const resolvedOffset =
      offset ?? (page ? (page - 1) * resolvedLimit : 0)

    return {
      nextOffset:
        resolvedOffset + resolvedLimit < rows.length
          ? resolvedOffset + resolvedLimit
          : undefined,
      nextPage:
        page && resolvedOffset + resolvedLimit < rows.length
          ? page + 1
          : undefined,
      rows: rows.slice(resolvedOffset, resolvedOffset + resolvedLimit),
      total: rows.length,
    }
  },
  label: "Static Workflow Trace",
})

function buildToyTraceRows({
  domain,
  runId,
  startTime,
  team,
  url,
}: {
  domain: string
  runId: string
  startTime: string
  team: string
  url: string
}): ToyTraceRow[] {
  const runSpanId = runId
  const loadBrandSpanId = `${runId}:load-brand`
  const scrapeUrlSpanId = `${runId}:scrape-url`
  const toTimestamp = (offsetMs: number) =>
    new Date(Date.parse(startTime) + offsetMs).toISOString()

  return [
    {
      type: "span",
      spanId: runSpanId,
      name: "Generate Report",
      resource: "workflow",
      startTime,
      endTime: toTimestamp(9_000),
      attributes: {
        environment: "local",
        runId,
        team,
      },
    },
    {
      type: "span",
      spanId: loadBrandSpanId,
      parentSpanId: runSpanId,
      name: "Load brand",
      resource: "database",
      startTime: toTimestamp(700),
      endTime: toTimestamp(2_100),
      activeStartTime: toTimestamp(1_100),
      attributes: {
        "db.statement": "select * from brands where domain = ?",
        domain,
        note: "The gap before activeStartTime renders the queued portion.",
      },
    },
    {
      type: "event",
      spanId: loadBrandSpanId,
      name: "cache lookup",
      timestamp: toTimestamp(900),
      attributes: {
        hit: false,
        kind: "plain marker",
        note: "No custom color and no vertical line. This is the default event marker.",
      },
    },
    {
      type: "event",
      spanId: loadBrandSpanId,
      name: "row returned",
      timestamp: toTimestamp(1_700),
      color: "#10b981",
      attributes: {
        colorMeaning: "green means a successful database milestone",
        rows: 1,
      },
    },
    {
      type: "span",
      spanId: scrapeUrlSpanId,
      parentSpanId: runSpanId,
      name: "Scrape URL",
      resource: "function",
      startTime: toTimestamp(2_600),
      endTime: toTimestamp(7_800),
      activeStartTime: toTimestamp(3_200),
      attributes: {
        model: "gpt-5.4-mini",
        url,
        worker: "scrape-07",
      },
    },
    {
      type: "event",
      spanId: scrapeUrlSpanId,
      name: "request started",
      timestamp: toTimestamp(3_350),
      color: "#f59e0b",
      attributes: {
        note: "Custom event color changes the diamond marker color.",
        phase: "network",
      },
    },
    {
      type: "event",
      spanId: scrapeUrlSpanId,
      name: "timeout warning",
      timestamp: toTimestamp(6_000),
      color: "#ef4444",
      showVerticalLine: true,
      attributes: {
        note: "showVerticalLine adds a guide line across the timeline to call the event out.",
        retryable: true,
        timeoutMs: 3000,
      },
    },
    {
      type: "event",
      spanId: runSpanId,
      name: "report assembled",
      timestamp: toTimestamp(8_400),
      color: "#6366f1",
      attributes: {
        sections: 4,
        summary: "A root-span event can mark a workflow milestone.",
      },
    },
  ]
}

